import { useMemo, useState, useEffect } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces, cities, types } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';
import MapView from '../components/MapView';
import Filters from '../components/Filters';

function useFavorites() {
  const [fav, setFav] = useState(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      return raw ? JSON.parse(raw) : [];
    } catch {
      return [];
    }
  });
  useEffect(() => {
    localStorage.setItem('wn:favorites', JSON.stringify(fav));
  }, [fav]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}

export default function Search() {
  const [filterValues, setFilterValues] = useState({ city: '', type: '', minPrice: '', maxPrice: '' });
  const { favorites, toggle } = useFavorites();
  const [sortBy, setSortBy] = useState('relevance');
  const [showMap, setShowMap] = useState(false);
  const [homeCity, setHomeCity] = useState(() => {
    try {
      return localStorage.getItem('wn:homeCity') || '';
    } catch { return ''; }
  });
  useEffect(() => {
    localStorage.setItem('wn:homeCity', homeCity);
  }, [homeCity]);

  const filtered = useMemo(() => {
    let result = spaces.filter((s) => {
      if (filterValues.city && s.city !== filterValues.city) return false;
      if (filterValues.type && s.type !== filterValues.type) return false;
      if (filterValues.minPrice && s.pricePerDay < Number(filterValues.minPrice)) return false;
      if (filterValues.maxPrice && s.pricePerDay > Number(filterValues.maxPrice)) return false;
      return true;
    });
    if (sortBy === 'price-asc') result = [...result].sort((a, b) => a.pricePerDay - b.pricePerDay);
    if (sortBy === 'price-desc') result = [...result].sort((a, b) => b.pricePerDay - a.pricePerDay);
    if (sortBy === 'rating-desc') result = [...result].sort((a, b) => b.rating - a.rating);
    return result;
  }, [filterValues, sortBy]);

  const commuteFor = (s) => {
    if (!homeCity) return undefined;
    const same = s.city === homeCity;
    const min = same ? 15 : 45;
    const max = same ? 35 : 90;
    return Math.floor(Math.random() * (max - min + 1)) + min;
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Hero Section */}
        <section className="relative overflow-hidden bg-gradient-to-b from-brand-50/40 via-white to-white">
          <div className="relative w-full px-6 md:px-12 lg:px-16 pt-12 pb-8">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-brand-500 to-brand-600 flex items-center justify-center shadow-lg">
                <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>
              <div>
                <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-gray-900">Explore Workspaces</h1>
                <p className="text-gray-600 mt-1">Find the perfect space for your team</p>
              </div>
            </div>
            
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
              <div className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/80 backdrop-blur border border-gray-200">
                <svg className="w-4 h-4 text-brand-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                <span className="text-sm font-semibold text-gray-900">{filtered.length}</span>
                <span className="text-sm text-gray-600">results found</span>
              </div>
              
              <div className="flex items-center gap-3 flex-wrap">
                <div className="relative">
                  <select
                    className="h-10 pl-10 pr-4 rounded-lg border border-gray-200 text-sm bg-white hover:border-brand-300 focus:outline-none focus:ring-2 focus:ring-brand-400 transition"
                    value={homeCity}
                    onChange={(e) => setHomeCity(e.target.value)}
                  >
                    <option value="">📍 Commute from: Not set</option>
                    {cities.map((c) => (
                      <option key={c} value={c}>{c}</option>
                    ))}
                  </select>
                  <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <div className="relative">
                  <select
                    className="h-10 pl-10 pr-4 rounded-lg border border-gray-200 text-sm bg-white hover:border-brand-300 focus:outline-none focus:ring-2 focus:ring-brand-400 transition"
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value)}
                  >
                    <option value="relevance">Sort: Relevance</option>
                    <option value="price-asc">Price: Low to High</option>
                    <option value="price-desc">Price: High to Low</option>
                    <option value="rating-desc">Rating: High to Low</option>
                  </select>
                  <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4h13M3 8h9m-9 4h6m4 0l4-4m0 0l4 4m-4-4v12" />
                  </svg>
                </div>
                <button
                  className={`h-10 px-4 rounded-lg border text-sm font-medium transition-all duration-200 flex items-center gap-2 ${showMap ? 'border-brand-600 text-brand-700 bg-brand-50 shadow-sm' : 'border-gray-200 text-gray-700 bg-white hover:border-brand-300 hover:bg-brand-50'}`}
                  onClick={() => setShowMap(!showMap)}
                >
                  {showMap ? (
                    <>
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" />
                      </svg>
                      List view
                    </>
                  ) : (
                    <>
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />
                      </svg>
                      Map view
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </section>

        <section className="w-full px-6 md:px-12 lg:px-16 py-6">
          <div className="md:sticky md:top-20 z-10 bg-white/95 backdrop-blur-md rounded-2xl p-5 border border-gray-100 shadow-lg">
            <Filters cities={cities} types={types} values={filterValues} onChange={setFilterValues} />
          </div>

          {!showMap ? (
            <div className="mt-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filtered.length === 0 ? (
                <div className="col-span-full py-16 text-center">
                  <div className="w-16 h-16 mx-auto rounded-full bg-gray-100 flex items-center justify-center mb-4">
                    <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-2">No spaces found</h3>
                  <p className="text-gray-600">Try adjusting your filters to see more results.</p>
                </div>
              ) : (
                filtered.map((s) => (
                  <SpaceCard key={s.id} space={s} onToggleFavorite={toggle} isFavorite={favorites.includes(s.id)} commuteMins={commuteFor(s)} />
                ))
              )}
            </div>
          ) : (
            <div className="mt-6 rounded-2xl overflow-hidden border border-gray-100 shadow-lg">
              <MapView spaces={filtered} />
            </div>
          )}
        </section>
      </main>
      <Footer />
    </div>
  );
}
